SELECT /* base.ec.pm :: PmEventItem :: selectList */ i.* , evt.event_nm AS event_nm , ste.site_nm AS site_nm , cd_eit.code_label AS target_type_cd_nm FROM pm_event_item i LEFT JOIN pm_event evt ON evt.event_id = i.event_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_eit ON cd_eit.code_grp = 'EVENT_ITEM_TARGET' AND cd_eit.code_value = i.target_type_cd
ORDER BY i.event_item_id ASC ORDER BY i.event_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pm :: PmEventItem :: selectPageList */ i.* , evt.event_nm AS event_nm , ste.site_nm AS site_nm , cd_eit.code_label AS target_type_cd_nm FROM pm_event_item i LEFT JOIN pm_event evt ON evt.event_id = i.event_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_eit ON cd_eit.code_grp = 'EVENT_ITEM_TARGET' AND cd_eit.code_value = i.target_type_cd
ORDER BY i.event_item_id ASC ORDER BY i.event_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

